final:
module RefModule(in, s, out);input wire[3: 0] in; 
  input wire[1: 0] s; 
  output wire out; 
  reg unused__out; 
  always @(in or s) 
  if(s == 2'b00) 
  unused__out = in[0]; 
  else if(s == 2'b01) 
  unused__out = in[1]; 
  else if(s == 2'b10) 
  unused__out = in[2]; 
  else if(s == 2'b11) 
  unused__out = in[3]; 
  else 
  unused__out = 1'b0; 
  assign out = unused__out; 
 endmodule
